arguments.argument:
if global.gamePaused=false
{
  if init=0 {init=1}
  
  arcTime+=1
  if arcTime>=1 and arcTime<=10 {direction+=4}
  else if arcTime>=11 and arcTime<=30 {direction-=4}
  else
  {
    direction+=4
    if arcTime>=40 {arcTime=0}
  }
  
  speed=bulletSpeed
  image_angle=direction
}
else {speed=0}
